package com.establo.controller;import com.establo.dto.MedicalRecordDto;import com.establo.service.MedicalRecordService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/medical-records") @RequiredArgsConstructor @PreAuthorize("hasAnyRole('ADMIN','VETERINARIAN')") public class MedicalRecordController {private final MedicalRecordService s;@GetMapping("/horse/{id}") List<MedicalRecordDto> byHorse(@PathVariable Long id){return s.byHorse(id);}@PostMapping ResponseEntity<MedicalRecordDto> create(@Valid @RequestBody MedicalRecordDto d){return ResponseEntity.status(201).body(s.create(d));}@PutMapping("/{id}") MedicalRecordDto update(@PathVariable Long id,@Valid @RequestBody MedicalRecordDto d){return s.update(id,d);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) void delete(@PathVariable Long id){s.delete(id);}}
